import React, { useEffect, useState } from "react";
import axios from "axios";

const LabourDashboard = () => {
  const [jobs, setJobs] = useState([]);

  const load = async () => {
    const res = await axios.get("http://localhost:5000/api/jobs/all");
    setJobs(res.data);
  };

  const accept = async (id) => {
    await axios.put(`http://localhost:5000/api/jobs/accept/${id}`);
    load();
  };

  const complete = async (id) => {
    await axios.put(`http://localhost:5000/api/jobs/complete/${id}`);
    load();
  };

  useEffect(() => {
    load();
  }, []);

  return (
    <div>
      <h2>Labour Dashboard</h2>

      {jobs.map(j => (
        <div key={j._id}>
          <h4>{j.title}</h4>
          <p>{j.status}</p>

          <button onClick={() => accept(j._id)}>Accept</button>
          <button onClick={() => complete(j._id)}>Complete</button>
        </div>
      ))}
    </div>
  );
};

export default LabourDashboard;
